function check_pause_function_exists(address caller) public {
    vm.assume(caller == owner);
    vm.prank(caller);
    // This call should succeed if pause() is properly implemented
    try entropyGenerator.pause() {
        assert(entropyGenerator.paused() == true);
    } catch {
        // If pause() doesn't exist or reverts for owner, this is a bug
        assert(false);
    }
}
